import React, { useState } from 'react';

export default function Accordion({ items, allowMultiple = false }) {
  const [activeIndices, setActiveIndices] = useState([]);

  const toggleIndex = (index) => {
    if (allowMultiple) {
      if (activeIndices.includes(index)) {
        setActiveIndices(activeIndices.filter(i => i !== index));
      } else {
        setActiveIndices([...activeIndices, index]);
      }
    } else {
      setActiveIndices(activeIndices.includes(index) ? [] : [index]);
    }
  };

  return (
    <div className="w-full max-w-md border border-gray-200 rounded-lg overflow-hidden bg-white shadow-sm">
      {items.map((item, idx) => {
        const isExpanded = activeIndices.includes(idx);
        return (
          <div key={idx} className="border-b border-gray-100 last:border-0">
            <button
              onClick={() => toggleIndex(idx)}
              className="w-full flex items-center justify-between px-5 py-4 text-left font-medium text-gray-800 hover:bg-gray-50 transition-colors"
            >
              <span>{item.header}</span>
              <svg
                className={`w-4 h-4 text-gray-500 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`}
                fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}
              >
                <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
              </svg>
            </button>
            <div className={`transition-all duration-300 overflow-hidden ${isExpanded ? 'max-h-96 px-5 py-4 border-t border-gray-50 bg-gray-50/50' : 'max-h-0'}`}>
              <p className="text-gray-600 text-sm leading-relaxed">{item.content}</p>
            </div>
          </div>
        );
      })}
    </div>
  );
}
